 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, ButtonVariant, Modal, Popover, PopoverPosition } from '@patternfly/react-core';
 6	import VMsByNamespacePopover from '@virtualmachines/actions/components/ConfirmMultipleVMActionsModal/components/VMsByNamespacePopover';
 7	import { getVMNamesByNamespace } from '@virtualmachines/actions/components/ConfirmMultipleVMActionsModal/utils/utils';
 8	
 9	import './ConfirmMultipleVMActionsModal.scss';
10	
11	type ConfirmMultipleVMActionsModalProps = {
12	  action: (vm: V1VirtualMachine) => Promise<string>;
13	  actionType: string;
14	  isOpen: boolean;
15	  onClose: () => void;
16	  vms: V1VirtualMachine[];
17	};
18	
19	const ConfirmMultipleVMActionsModal: FC<ConfirmMultipleVMActionsModalProps> = ({
20	  action,
21	  actionType,
22	  isOpen,
23	  onClose,
24	  vms,
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	  const vmsByNamespace = getVMNamesByNamespace(vms);
28	  const numVMs = vms?.length;
29	  const numVMNamespaces = Object.keys(vmsByNamespace)?.length;
30	
31	  const submitHandler = () => {
32	    vms?.forEach((vm) => {
33	      action(vm);
34	    });
35	    onClose();
36	  };
37	
38	  return (
39	    <Modal
40	      actions={[
41	        <Button key="confirm" onClick={submitHandler} variant={ButtonVariant.primary}>
42	          {t(actionType)}
43	        </Button>,
44	        <Button key="cancel" onClick={onClose} variant="link">
45	          {t('Cancel')}
46	        </Button>,
47	      ]}
48	      className="confirm-multiple-vm-actions-modal"
49	      isOpen={isOpen}
50	      onClose={onClose}
51	      onSubmit={() => submitHandler()}
52	      title={t(`${actionType} ${numVMs} VirtualMachines?`)}
53	      variant={'small'}
54	    >
55	      {t('Are you sure you want to stop ')}
56	      <Popover
57	        bodyContent={<VMsByNamespacePopover vmsByNamespace={vmsByNamespace} />}
58	        className="confirm-multiple-vm-actions-modal__popover"
59	        position={PopoverPosition.right}
60	      >
61	        <a>
62	          {t('{{numVMs}} VirtualMachines in {{numVMNamespaces}} namespaces?', {
63	            numVMNamespaces,
64	            numVMs,
65	          })}
66	        </a>
67	      </Popover>
68	    </Modal>
69	  );
70	};
71	
72	export default ConfirmMultipleVMActionsModal;

